package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormatWithMultipleValues() {
        String result = csvFormat.format("a", "b", "c");
        // Default delimiter is comma, default quote char is double quote, record separator is CRLF
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithNullValue() {
        CSVFormat format = csvFormat.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormatWithSingleValue() {
        String result = csvFormat.format("single");
        assertEquals("single", result);
    }

    @Test
    void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Create a spy of CSVPrinter that throws IOException on printRecord
        CSVPrinter spyPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(spyPrinter).printRecord(any());

        // Use reflection to replace the CSVPrinter constructor call inside CSVFormat.format
        // by temporarily overriding the CSVFormat.print method to return our spy

        // Create a subclass of CSVFormat to override print(Appendable) to return our spy
        CSVFormat csvFormatSpy = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter()
        ) {
            @Override
            public CSVPrinter print(final Appendable out) {
                return spyPrinter;
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatSpy.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
